import{_ as t,o,c as n,a2 as i}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"Droid — Context Management","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/droid/context-management.md","filePath":"research/agents/droid/context-management.md"}'),a={name:"research/agents/droid/context-management.md"};function r(s,e,c,l,d,h){return o(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="droid-—-context-management" tabindex="-1">Droid — Context Management <a class="header-anchor" href="#droid-—-context-management" aria-label="Permalink to &quot;Droid — Context Management&quot;">​</a></h1><blockquote><p>Factory&#39;s compaction engine is Droid&#39;s most differentiated capability — enabling multi-week sessions, cross-interface context persistence, and &quot;teach once, build many&quot; workflows.</p></blockquote><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>Context window management is the central challenge for every coding agent. Models have finite token limits, and real engineering work often spans:</p><ul><li>Large codebases with hundreds or thousands of files</li><li>Multi-day tasks that accumulate extensive conversation history</li><li>Cross-repository dependencies and upstream packages</li><li>Design decisions, reviewer feedback, and architectural rationale</li></ul><p>Most agents handle this with simple truncation, sliding windows, or forced session resets. Factory took a fundamentally different approach.</p><h2 id="the-compaction-engine" tabindex="-1">The Compaction Engine <a class="header-anchor" href="#the-compaction-engine" aria-label="Permalink to &quot;The Compaction Engine&quot;">​</a></h2><p>Factory&#39;s proprietary <strong>compaction engine</strong> is what enables Droid&#39;s multi-week sessions. Based on public information (primarily the Chainguard case study and docs), the engine works through:</p><h3 id="incremental-compression-with-anchor-points" tabindex="-1">Incremental Compression with Anchor Points <a class="header-anchor" href="#incremental-compression-with-anchor-points" aria-label="Permalink to &quot;Incremental Compression with Anchor Points&quot;">​</a></h3><p>Rather than discarding old context or performing naive summarization, the compaction engine:</p><ol><li><strong>Identifies anchor points</strong> — key decisions, important code changes, critical context that must persist.</li><li><strong>Incrementally compresses</strong> surrounding context — reducing verbosity while preserving semantic meaning.</li><li><strong>Maintains referenceability</strong> — compressed context can be recalled when relevant, not lost entirely.</li></ol><p>The result is described by Factory&#39;s docs as &quot;near-perfect context&quot; — developers experience it as working with a colleague who &quot;just remembers&quot; what&#39;s been discussed.</p><h3 id="how-it-differs-from-competitors" tabindex="-1">How It Differs from Competitors <a class="header-anchor" href="#how-it-differs-from-competitors" aria-label="Permalink to &quot;How It Differs from Competitors&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Approach</th><th>Agent</th><th>Limitation</th></tr></thead><tbody><tr><td>Session reset</td><td>Most agents</td><td>Lose all context between sessions</td></tr><tr><td>Sliding window</td><td>Basic agents</td><td>Lose early context as conversation grows</td></tr><tr><td>Manual curation</td><td>Claude Code (CLAUDE.md)</td><td>Requires developer to maintain context files</td></tr><tr><td>Memory MCPs/tools</td><td>Various</td><td>Josh Wolf (Chainguard): &quot;None of them offered what they promised&quot;</td></tr><tr><td><strong>Compaction</strong></td><td><strong>Droid</strong></td><td><strong>Automatic, incremental, preserves weeks of context</strong></td></tr></tbody></table><h3 id="real-world-validation" tabindex="-1">Real-World Validation <a class="header-anchor" href="#real-world-validation" aria-label="Permalink to &quot;Real-World Validation&quot;">​</a></h3><p>From the Chainguard case study:</p><blockquote><p>&quot;I keep telling Matt (Moore, CTO Chainguard), I&#39;ve had multiple Droid sessions going on for weeks. Because compaction is just that good.&quot;</p></blockquote><blockquote><p>&quot;When you don&#39;t have to think about context windows, you can treat Droid like a colleague that just remembers what you&#39;ve been talking about.&quot;</p></blockquote><p>Key metrics from the case study:</p><ul><li><strong>2-week continuous session</strong> without context degradation</li><li><strong>6 repositories</strong> managed within sessions</li><li><strong>80 packages built</strong> using the &quot;teach once&quot; pattern</li></ul><h2 id="context-confidence" tabindex="-1">Context-Confidence <a class="header-anchor" href="#context-confidence" aria-label="Permalink to &quot;Context-Confidence&quot;">​</a></h2><p>Factory&#39;s documentation describes their context approach as <strong>&quot;context-confidence&quot;</strong> — compressing incrementally with anchor points for near-perfect context. This suggests a confidence-scored system where:</p><ul><li>Each piece of context has an associated relevance/confidence score.</li><li>Higher-confidence context (anchor points) is preserved at full fidelity.</li><li>Lower-confidence context is progressively compressed.</li><li>The system dynamically adjusts based on current task relevance.</li></ul><h2 id="multi-source-context-assembly" tabindex="-1">Multi-Source Context Assembly <a class="header-anchor" href="#multi-source-context-assembly" aria-label="Permalink to &quot;Multi-Source Context Assembly&quot;">​</a></h2><p>Droid doesn&#39;t just manage conversation context — it assembles context from multiple sources:</p><h3 id="code-context" tabindex="-1">Code Context <a class="header-anchor" href="#code-context" aria-label="Permalink to &quot;Code Context&quot;">​</a></h3><ul><li>Repository structure and file contents</li><li>Git history and diffs</li><li>Cross-repository references (multiple repos in a single session)</li></ul><h3 id="project-context-via-integrations" tabindex="-1">Project Context (via Integrations) <a class="header-anchor" href="#project-context-via-integrations" aria-label="Permalink to &quot;Project Context (via Integrations)&quot;">​</a></h3><ul><li><strong>Jira/Linear</strong>: Task descriptions, acceptance criteria, story points</li><li><strong>Notion/Confluence/Google Drive</strong>: Design documents, architectural decisions, team knowledge</li><li><strong>Sentry/PagerDuty</strong>: Error details, stack traces, incident history</li></ul><h3 id="session-context" tabindex="-1">Session Context <a class="header-anchor" href="#session-context" aria-label="Permalink to &quot;Session Context&quot;">​</a></h3><ul><li>Accumulated conversation history (compressed via compaction)</li><li>Teaching interactions (&quot;I showed Droid how to build a package once&quot;)</li><li>Review feedback and decision rationale</li></ul><h3 id="configuration-context" tabindex="-1">Configuration Context <a class="header-anchor" href="#configuration-context" aria-label="Permalink to &quot;Configuration Context&quot;">​</a></h3><ul><li><code>.droid.yaml</code> review guidelines and path-specific rules</li><li>Repository-specific patterns and conventions</li><li>Team-level model preferences</li></ul><h2 id="teach-once-build-many-pattern" tabindex="-1">&quot;Teach Once, Build Many&quot; Pattern <a class="header-anchor" href="#teach-once-build-many-pattern" aria-label="Permalink to &quot;&quot;Teach Once, Build Many&quot; Pattern&quot;">​</a></h2><p>One of the most powerful context management patterns enabled by compaction:</p><ol><li>Developer works with Droid to build something the first time, explaining patterns and decisions.</li><li>Droid learns the pattern within the session context.</li><li>For subsequent similar tasks, Droid applies the pattern independently.</li></ol><p>From Chainguard:</p><blockquote><p>&quot;I can start a session with Droid, as I would with a junior engineer, and naturally teach it to perform a task once or twice, and we&#39;ll work on it together. Then I have a senior engineer that can operate independently with minimal intervention.&quot;</p></blockquote><p>This was specifically used to build <strong>80 open-source packages</strong> — the developer taught the pattern for a few, then Droid replicated it across the remaining packages with minimal guidance.</p><h2 id="cross-interface-context-persistence" tabindex="-1">Cross-Interface Context Persistence <a class="header-anchor" href="#cross-interface-context-persistence" aria-label="Permalink to &quot;Cross-Interface Context Persistence&quot;">​</a></h2><p>Because the agent core is interface-agnostic, context persists across interface transitions:</p><ul><li>Start a brainstorming session in the <strong>web workspace</strong>.</li><li>Continue implementation in the <strong>CLI</strong>.</li><li>Review the PR through <strong>GitHub integration</strong>.</li><li>Discuss feedback in <strong>Slack</strong>.</li></ul><p>The compaction engine maintains continuity throughout — the context of why a decision was made, what alternatives were considered, and what reviewer feedback was given all stays accessible regardless of which interface the developer uses.</p><h2 id="token-economics-and-model-routing" tabindex="-1">Token Economics and Model Routing <a class="header-anchor" href="#token-economics-and-model-routing" aria-label="Permalink to &quot;Token Economics and Model Routing&quot;">​</a></h2><p>Context management intersects with model routing for cost optimization:</p><ul><li>Factory Analytics tracks <strong>token consumption</strong> by model, input/output split, and <strong>cache efficiency</strong>.</li><li>Teams can route context-heavy reasoning work to frontier models (Opus 4.6, o3) while routing execution to cost-efficient models (GLM-5, Kimi-K2.5).</li><li>Cache efficiency metrics suggest the system optimizes for prompt caching — keeping common context in cached prefixes to reduce costs.</li></ul><h2 id="no-manual-context-curation-required" tabindex="-1">No Manual Context Curation Required <a class="header-anchor" href="#no-manual-context-curation-required" aria-label="Permalink to &quot;No Manual Context Curation Required&quot;">​</a></h2><p>A key differentiator versus competitors: developers don&#39;t need to manually curate context. From the Chainguard case study:</p><blockquote><p>&quot;The thing I dislike about other CLI agents is that you have to meticulously curate things like skills and commands to effectively seed the context window to perform repeatable tasks. I don&#39;t have to do any of that with Droid.&quot;</p></blockquote><p>This is a direct contrast to agents that rely on:</p><ul><li><code>CLAUDE.md</code> files (Claude Code)</li><li>Custom instructions (Cursor)</li><li>Memory MCPs (various)</li><li>Manual <code>/add</code> file management (Aider)</li></ul><p>Droid&#39;s compaction engine handles context curation automatically, reducing the &quot;meta-work&quot; of using an AI coding agent.</p>',52)])])}const p=t(a,[["render",r]]);export{m as __pageData,p as default};
